#include<bits/stdc++.h>
#define F(a,b,c) for(int a=b;a<=c;a++) 
#define Sqr(a) ((a)*(a))
#define mp make_pair
#define pdi pair<double,int>
using namespace std;
const double EPS=1e-4;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}double d[105];bool mark[105];int n,m,x[105],y[105],head[105],tot;
struct Edge{int v;double w;int nxt;}edge[20050];
void addedge(int u,int v,double w){edge[++tot]=(Edge){v,w,head[u]};head[u]=tot;}
bool same(double a,double b){return fabs(a-b)<=EPS;}
double dis(int a,int b){return sqrt(Sqr(x[a]-x[b])+Sqr(y[a]-y[b]));}
void dijkstra(int s){
	F(i,1,n)d[i]=2147483647.2147483647;
	priority_queue<pdi,vector<pdi >,greater<pdi> >que;
	que.push(mp(0,s));d[s]=0;
	while(!que.empty()){
		int h=que.top().second;
		if(!same(que.top().first,d[h])){
			que.pop();continue;
		}que.pop(),mark[h]=1;
		for(int i=head[h];i;i=edge[i].nxt){
			int v=edge[i].v;if(mark[v])continue;
			if(d[h]+edge[i].w<d[v])d[v]=d[h]+edge[i].w,que.push(mp(d[v],v));
		}
	}
}int main(void){
	n=read();F(i,1,n)x[i]=read(),y[i]=read();
	m=read();F(i,1,m){int u,v;u=read(),v=read();addedge(u,v,dis(u,v));addedge(v,u,dis(v,u));}
	int s=read(),t=read();dijkstra(s);printf("%.2lf\n",d[t]);return false;
}
